"use client";

import { useState, useCallback, useRef } from "react";
import * as XLSX from "xlsx";
import { calculateOT } from "@/utils/calculateOT";

type ShiftType = "shift1" | "shift2" | "shift3" | "office";

const SHIFT_CONFIG: Record<ShiftType, { label: string; normalEnd: string }> = {
  shift1: { label: "Shift 1 (06:00-14:00)", normalEnd: "14:00" },
  shift2: { label: "Shift 2 (14:00-22:00)", normalEnd: "22:00" },
  shift3: { label: "Shift 3 (22:00-06:00)", normalEnd: "06:00" },
  office: { label: "Office (07:30-17:00)", normalEnd: "17:00" },
};

interface DayGroup {
  day: number;
  startCol: number;
  colIn: number;
  colBreakOut1: number;
  colBreakIn1: number;
  colBreakOut2: number;
  colBreakIn2: number;
  colOut: number;
}

interface DayRecord {
  day: number;
  inTime: string;
  breakOut1: string;
  breakIn1: string;
  breakOut2: string;
  breakIn2: string;
  outTime: string;
}

interface EmployeeResult {
  nik: string;
  nama: string;
  department: string;
  shift: string;
  normalEnd: string;
  days: DayRecord[];
  totalOT1: number;
  totalOT2: number;
  totalOTMinutes: number;
  totalOTHours: number;
}

export default function Home() {
  const [file, setFile] = useState<File | null>(null);
  const [sheets, setSheets] = useState<string[]>([]);
  const [selectedSheet, setSelectedSheet] = useState("");
  const [rawPreview, setRawPreview] = useState<string[][]>([]);
  const [headerRow, setHeaderRow] = useState(0);
  const [shiftType, setShiftType] = useState<ShiftType>("shift1");
  const [dayGroups, setDayGroups] = useState<DayGroup[]>([]);
  const [results, setResults] = useState<EmployeeResult[]>([]);
  const [previewRows, setPreviewRows] = useState<EmployeeResult[]>([]);
  const [processed, setProcessed] = useState(false);
  const [error, setError] = useState("");
  const [step, setStep] = useState<"upload" | "config" | "done">("upload");

  interface UnifiedRow {
    shift: string;
    nik: string;
    nama: string;
    department: string;
    day: number;
    inTime: string;
    breakOut1: string;
    breakIn1: string;
    breakOut2: string;
    breakIn2: string;
    outTime: string;
    normalEnd: string;
    otMinutes: number;
    otHours: number;
    OT1: number;
    OT2: number;
  }

  const [unifiedResults, setUnifiedResults] = useState<UnifiedRow[]>([]);
  const [unifiedPreview, setUnifiedPreview] = useState<UnifiedRow[]>([]);
  const [employeeResults, setEmployeeResults] = useState<EmployeeResult[]>([]);
  const rawDataRef = useRef<Record<string, unknown[][]>>({});
  const colsInfoRef = useRef<{ start: number; keys: string[] }[]>([]);

  const SHIFT_KEYS: ShiftType[] = ["shift1", "shift2", "shift3", "office"];

  const handleFileChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      const f = e.target.files?.[0];
      if (!f) return;
      setFile(f);
      setError("");
      setProcessed(false);
      setResults([]);
      setStep("upload");

      const reader = new FileReader();
      reader.onload = (ev) => {
        try {
          const buffer = ev.target?.result as ArrayBuffer;
          const workbook = XLSX.read(buffer, { type: "array" });
          const names = workbook.SheetNames;
          setSheets(names);

          const allRaw: Record<string, unknown[][]> = {};
          names.forEach((name) => {
            const ws = workbook.Sheets[name];
            const raw: unknown[][] = XLSX.utils.sheet_to_json(ws, {
              header: 1,
              defval: "",
            });
            allRaw[name] = raw;
          });
          rawDataRef.current = allRaw;

          if (names.length > 0) {
            setSelectedSheet(names[0]);
            loadSheetPreview(allRaw, names[0]);
          }
        } catch {
          setError("无法读取文件内容");
        }
      };
      reader.readAsArrayBuffer(f);
    },
    []
  );

  const loadSheetPreview = (
    allRaw: Record<string, unknown[][]>,
    name: string
  ) => {
    const raw = allRaw[name];
    if (!raw) return;
    const sample = raw.slice(0, 15).map((r) =>
      (r as unknown[]).map((c) => String(c))
    );
    setRawPreview(sample);
    setHeaderRow(0);
    setDayGroups([]);
    setStep("upload");
  };

  const handleSheetChange = (name: string) => {
    setSelectedSheet(name);
    loadSheetPreview(rawDataRef.current, name);
  };

  const handleApplyHeaderRow = useCallback(() => {
    const allRaw = rawDataRef.current;
    const raw = allRaw[selectedSheet];
    if (!raw || raw.length === 0) return;

    if (headerRow < 0 || headerRow >= raw.length) {
      setError(`行号 ${headerRow} 超出范围 (0-${raw.length - 1})`);
      return;
    }

    const headers = raw[headerRow] as unknown[];

    // Auto-detect day groups
    const groups: DayGroup[] = [];
    let col = 0;
    while (col < headers.length) {
      const val = String(headers[col] ?? "").trim();
      const num = parseInt(val, 10);
      if (!isNaN(num) && num >= 1 && num <= 31) {
        const dayStart = col;
        groups.push({
          day: num,
          startCol: dayStart,
          colIn: dayStart + 1,
          colBreakOut1: dayStart + 2,
          colBreakIn1: dayStart + 3,
          colBreakOut2: dayStart + 4,
          colBreakIn2: dayStart + 5,
          colOut: dayStart + 6,
        });
        col += 13;
      } else {
        col++;
      }
    }

    if (groups.length === 0) {
      setError("未检测到日期列（1-31），请确认标题行是否正确");
      return;
    }

    // Build column info for preview
    const day0 = groups[0];
    const colNames = ["IN", "BREAK OUT 1", "BREAK IN 1", "BREAK OUT 2", "BREAK IN 2", "OUT"];
    const colIndices = [day0.colIn, day0.colBreakOut1, day0.colBreakIn1, day0.colBreakOut2, day0.colBreakIn2, day0.colOut];
    const colsInfo = colNames.map((n, i) => ({ start: colIndices[i], keys: [n] }));
    colsInfoRef.current = colsInfo;

    setDayGroups(groups);
    setError("");
    setStep("config");
  }, [selectedSheet, headerRow]);

  const handleProcess = useCallback(() => {
    const allRaw = rawDataRef.current;
    const raw = allRaw[selectedSheet];
    if (!raw || dayGroups.length === 0) return;

    const normalEnd = SHIFT_CONFIG[shiftType].normalEnd;

    // Get data rows
    const dataRows = raw.slice(headerRow + 1).filter((r) => {
      const row = r as unknown[];
      return (
        row.some((c) => c !== "" && c !== undefined && c !== null) &&
        String(row[0] ?? "").trim() !== ""
      );
    });

    const employeeResults: EmployeeResult[] = [];

    for (const r of dataRows) {
      const row = r as unknown[];
      const nik = String(row[1] ?? "").trim();
      const nama = String(row[2] ?? "").trim();
      const dept = String(row[5] ?? "").trim();

      if (!nik) continue;

      const days: DayRecord[] = [];
      let totalOT1 = 0;
      let totalOT2 = 0;

      for (const dg of dayGroups) {
        const outVal = row[dg.colOut];
        const result = calculateOT(normalEnd, outVal as string | number | undefined);
        totalOT1 += result.OT1;
        totalOT2 += result.OT2;

        days.push({
          day: dg.day,
          inTime: String(row[dg.colIn] ?? ""),
          breakOut1: String(row[dg.colBreakOut1] ?? ""),
          breakIn1: String(row[dg.colBreakIn1] ?? ""),
          breakOut2: String(row[dg.colBreakOut2] ?? ""),
          breakIn2: String(row[dg.colBreakIn2] ?? ""),
          outTime: String(row[dg.colOut] ?? ""),
        });
      }

      const totalOTMinutes = Math.round((totalOT1 + totalOT2) * 60);
      const totalOTHours = parseFloat(((totalOT1 + totalOT2) / 1).toFixed(2));

      employeeResults.push({
        nik,
        nama,
        department: dept,
        shift: SHIFT_CONFIG[shiftType].label,
        normalEnd,
        days,
        totalOT1,
        totalOT2,
        totalOTMinutes,
        totalOTHours,
      });
    }

    // Unified table: one row per employee per day
    const unified: UnifiedRow[] = [];
    for (const emp of employeeResults) {
      for (const d of emp.days) {
        const result = calculateOT(normalEnd, d.outTime as string | number | undefined);
        const hasData = d.inTime || d.outTime || d.breakOut1 || d.breakIn1 || d.breakOut2 || d.breakIn2;
        const otMinutes = (result.OT1 + result.OT2) * 60;
        const otHours = (result.OT1 + result.OT2);
        unified.push({
          shift: emp.shift,
          nik: emp.nik,
          nama: emp.nama,
          department: emp.department,
          day: d.day,
          inTime: d.inTime,
          breakOut1: d.breakOut1,
          breakIn1: d.breakIn1,
          breakOut2: d.breakOut2,
          breakIn2: d.breakIn2,
          outTime: d.outTime,
          normalEnd: emp.normalEnd,
          otMinutes: hasData ? otMinutes : 0,
          otHours: hasData ? parseFloat(otHours.toFixed(2)) : 0,
          OT1: hasData ? result.OT1 : 0,
          OT2: hasData ? result.OT2 : 0,
        });
      }
    }

    setUnifiedResults(unified);
    setUnifiedPreview(unified.slice(0, 20));
    setEmployeeResults(employeeResults);
    setProcessed(true);
    setStep("done");
    setError("");
  }, [selectedSheet, headerRow, shiftType, dayGroups]);

  // For download, use unified table (one row per employee per day)
  const handleDownload = useCallback(() => {
    if (unifiedResults.length === 0) return;

    const exportData = unifiedResults.map((r) => ({
      班次: r.shift,
      NIK: r.nik,
      姓名: r.nama,
      部门: r.department,
      日期: `Day ${r.day}`,
      上班打卡: r.inTime,
      休息开始1: r.breakOut1,
      休息结束1: r.breakIn1,
      休息开始2: r.breakOut2,
      休息结束2: r.breakIn2,
      下班打卡: r.outTime,
      正常下班时间: r.normalEnd,
      加班分钟: r.otMinutes,
      加班小时: r.otHours,
      OT1: r.OT1,
      OT2: r.OT2,
    }));

    const ws = XLSX.utils.json_to_sheet(exportData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "OT Results");
    XLSX.writeFile(wb, "OT_calculation_all_days.xlsx");
  }, [unifiedResults]);

  const totalEmployees = employeeResults.length;
  const totalRows = unifiedResults.length;
  const totalOT1 = unifiedResults.reduce((s, r) => s + r.OT1, 0);
  const totalOT2 = unifiedResults.reduce((s, r) => s + r.OT2, 0);
  const totalOTMin = unifiedResults.reduce((s, r) => s + r.otMinutes, 0);

  return (
    <main className="min-h-screen flex items-start justify-center pt-6 px-4 pb-12">
      <div className="w-full max-w-6xl bg-white rounded-xl shadow-sm border border-slate-200 p-8">
        <h1 className="text-2xl font-semibold text-slate-800 mb-2">
          考勤加班计算工具
        </h1>
        <p className="text-sm text-slate-500 mb-6">
          自动检测所有日期，统一输出含中途打卡和加班时长的汇总表
        </p>

        <div className="space-y-6">
          {/* Step 1: Upload */}
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              ① 选择文件
            </label>
            <label className="flex flex-col items-center justify-center w-full h-28 border-2 border-dashed border-slate-300 rounded-lg cursor-pointer bg-slate-50 hover:bg-slate-100 transition-colors">
              <div className="flex flex-col items-center justify-center">
                <svg
                  className="w-7 h-7 mb-1 text-slate-400"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={1.5}
                    d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"
                  />
                </svg>
                <p className="text-sm text-slate-500">
                  {file ? file.name : "点击上传 Excel"}
                </p>
              </div>
              <input
                type="file"
                className="hidden"
                accept=".xlsx,.xls,.csv"
                onChange={handleFileChange}
              />
            </label>
          </div>

          {sheets.length > 0 && step !== "done" && (
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                ② 选择数据表
              </label>
              <div className="flex flex-wrap gap-2 mb-3">
                {sheets.map((name) => (
                  <button
                    key={name}
                    onClick={() => handleSheetChange(name)}
                    className={`px-3 py-1.5 text-sm rounded-lg border transition-colors cursor-pointer ${
                      selectedSheet === name
                        ? "bg-blue-600 text-white border-blue-600"
                        : "bg-white text-slate-600 border-slate-300 hover:bg-slate-50"
                    }`}
                  >
                    {name}
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Raw preview + header row */}
          {rawPreview.length > 0 && step === "upload" && (
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-2">
                ③ 设置标题行
              </label>
              <div className="flex items-center gap-3 mb-3">
                <span className="text-sm text-slate-500">标题行号：</span>
                <input
                  type="number"
                  value={headerRow}
                  onChange={(e) => setHeaderRow(Number(e.target.value))}
                  className="w-20 px-3 py-1.5 border border-slate-300 rounded-lg text-sm text-center focus:outline-none focus:ring-2 focus:ring-blue-500"
                  min={0}
                  max={rawPreview.length - 1}
                />
                <span className="text-xs text-slate-400">
                  （0 ~ {rawPreview.length - 1}）
                </span>
                <button
                  onClick={handleApplyHeaderRow}
                  className="px-4 py-1.5 bg-blue-600 text-white text-sm rounded-lg font-medium hover:bg-blue-700 transition-colors cursor-pointer"
                >
                  应用
                </button>
              </div>
              <div className="overflow-x-auto border border-slate-200 rounded-lg max-h-48">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="bg-slate-50">
                      <th className="px-2 py-1 text-left font-medium text-slate-500 border-r border-slate-200 w-12">
                        #
                      </th>
                      {rawPreview[0]
                        ?.slice(0, 12)
                        .map((_, ci) => (
                          <th
                            key={ci}
                            className="px-2 py-1 text-left font-medium text-slate-500 whitespace-nowrap border-r border-slate-200"
                          >
                            {ci}
                          </th>
                        ))}
                      {rawPreview[0]?.length > 12 && (
                        <th className="px-2 py-1 text-left font-medium text-slate-400">
                          ...
                        </th>
                      )}
                    </tr>
                  </thead>
                  <tbody>
                    {rawPreview.map((row, ri) => (
                      <tr
                        key={ri}
                        className={`border-b border-slate-100 ${
                          ri === headerRow ? "bg-blue-50 font-semibold" : ""
                        }`}
                      >
                        <td className="px-2 py-1 text-slate-400 border-r border-slate-200">
                          {ri}
                        </td>
                        {row.slice(0, 12).map((cell, ci) => (
                          <td
                            key={ci}
                            className="px-2 py-1 text-slate-600 whitespace-nowrap border-r border-slate-200 max-w-40 truncate"
                          >
                            {cell}
                          </td>
                        ))}
                        {row.length > 12 && (
                          <td className="px-2 py-1 text-slate-400">...</td>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Step config */}
          {step === "config" && (
            <div>
              <h2 className="text-sm font-semibold text-slate-700 mb-3">
                ④ 配置并处理
              </h2>

              {dayGroups.length > 0 && (
                <div className="mb-3 text-sm text-slate-500 bg-slate-50 px-3 py-2 rounded-lg">
                  已自动检测到 <strong>{dayGroups.length}</strong> 天的打卡数据
                  （Day {dayGroups[0].day} ~ Day{" "}
                  {dayGroups[dayGroups.length - 1].day}）
                </div>
              )}

              <div className="mb-4">
                <label className="block text-sm font-medium text-slate-700 mb-1">
                  班次类型
                </label>
                <select
                  value={shiftType}
                  onChange={(e) => setShiftType(e.target.value as ShiftType)}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                >
                  {SHIFT_KEYS.map((key) => (
                    <option key={key} value={key}>
                      {SHIFT_CONFIG[key].label} → 正常下班{" "}
                      {SHIFT_CONFIG[key].normalEnd}
                    </option>
                  ))}
                </select>
              </div>

              <button
                onClick={handleProcess}
                className="w-full py-2.5 bg-emerald-600 text-white rounded-lg font-medium hover:bg-emerald-700 transition-colors cursor-pointer"
              >
                处理全部 {dayGroups.length} 天数据
              </button>
            </div>
          )}

          {error && (
            <div className="p-3 bg-red-50 text-red-700 text-sm rounded-lg border border-red-200">
              {error}
            </div>
          )}

          {/* Results */}
          {processed && step === "done" && (
            <div>
              <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
                <div className="flex items-center gap-4">
                  <h2 className="text-sm font-semibold text-slate-700">
                    汇总结果
                  </h2>
                  <span className="text-xs text-slate-500">
                    {totalEmployees} 人 · {totalRows} 条记录
                  </span>
                  <span className="text-xs text-slate-500">
                    OT1 合计:{" "}
                    <strong className="text-blue-600">{totalOT1}</strong>
                  </span>
                  <span className="text-xs text-slate-500">
                    OT2 合计:{" "}
                    <strong className="text-blue-600">{totalOT2}</strong>
                  </span>
                  <span className="text-xs text-slate-500">
                    总加班分钟:{" "}
                    <strong className="text-blue-600">{totalOTMin}</strong>
                  </span>
                </div>
                <button
                  onClick={handleDownload}
                  className="px-4 py-2 bg-emerald-600 text-white text-sm rounded-lg font-medium hover:bg-emerald-700 transition-colors cursor-pointer whitespace-nowrap"
                >
                  下载汇总表 (Excel)
                </button>
              </div>

              {/* Summary by shift */}
              <div className="flex flex-wrap gap-2 mb-3">
                {SHIFT_KEYS.map((key) => {
                  const label = SHIFT_CONFIG[key].label;
                  const rows = unifiedResults.filter((r) => r.shift === label);
                  if (rows.length === 0) return null;
                  const sOT1 = rows.reduce((s, r) => s + r.OT1, 0);
                  const sOT2 = rows.reduce((s, r) => s + r.OT2, 0);
                  return (
                    <div
                      key={key}
                      className="text-xs text-slate-500 bg-slate-50 px-3 py-1.5 rounded-lg"
                    >
                      {label}: {rows.length} 条 · OT1={sOT1} · OT2={sOT2}
                    </div>
                  );
                })}
              </div>

              <div className="overflow-x-auto border border-slate-200 rounded-lg max-h-96">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="bg-slate-50">
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        班次
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        NIK
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        姓名
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        日期
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        上班
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        休1始
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        休1终
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        休2始
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        休2终
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        下班
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        正常下班
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        加班分
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        加班时
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        OT1
                      </th>
                      <th className="px-2 py-1 text-left font-medium text-slate-600 whitespace-nowrap border-b border-slate-200">
                        OT2
                      </th>
                    </tr>
                  </thead>
                  <tbody>
                    {unifiedPreview.map((row, i) => (
                      <tr
                        key={i}
                        className="border-b border-slate-100 last:border-0 hover:bg-slate-50"
                      >
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.shift}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.nik}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.nama}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          Day {row.day}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.inTime || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.breakOut1 || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.breakIn1 || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.breakOut2 || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.breakIn2 || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.outTime || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap">
                          {row.normalEnd}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap font-medium">
                          {row.otMinutes || "-"}
                        </td>
                        <td className="px-2 py-1 text-slate-600 whitespace-nowrap font-medium">
                          {row.otHours || "-"}
                        </td>
                        <td className="px-2 py-1 text-blue-600 whitespace-nowrap font-medium">
                          {row.OT1}
                        </td>
                        <td className="px-2 py-1 text-blue-600 whitespace-nowrap font-medium">
                          {row.OT2}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>

              <button
                onClick={() => {
                  setStep("upload");
                  setProcessed(false);
                  setResults([]);
                  setUnifiedResults([]);
                  setUnifiedPreview([]);
                  setEmployeeResults([]);
                  setDayGroups([]);
                }}
                className="mt-4 px-4 py-2 border border-slate-300 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors cursor-pointer"
              >
                重新开始
              </button>
            </div>
          )}
        </div>
      </div>
    </main>
  );
}
